package com.user.servlet; import com.DB.DBConnect; import com.DAO.CartDAOImpl; import javax.servlet.annotation.WebServlet; import javax.servlet.http.*; import java.io.*;
@WebServlet("/remove_book") public class RemoveBookCart extends HttpServlet {protected void doGet(HttpServletRequest r,HttpServletResponse p)throws IOException{try(var c=DBConnect.getConn()){int bid=Integer.parseInt(r.getParameter("bid")),uid=Integer.parseInt(r.getParameter("uid")),cid=Integer.parseInt(r.getParameter("cid"));r.getSession().setAttribute(new CartDAOImpl(c).deleteBook(bid,uid,cid)?"succMsg":"failedMsg","Cart updated");}catch(Exception e){r.getSession().setAttribute("failedMsg",e.getMessage());}p.sendRedirect("checkout.jsp");}}
